<?php
if(session_status()===PHP_SESSION_NONE)session_start();if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}if(!in_array($_SESSION['user_type']??'', ['admin','gestionnaire'],true)){header('Location: dashboard.php');exit;}require_once __DIR__.'/../config/database.php';function ph($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
$payments=fetchAll('SELECT p.*,o.order_number,o.total_amount,t.number table_number FROM payments p JOIN orders o ON o.id=p.order_id LEFT JOIN tables t ON t.id=o.table_id WHERE p.supprimer=0 ORDER BY p.payment_date DESC,p.id DESC');$orders=fetchAll("SELECT o.id,o.order_number,o.total_amount,o.payment_status,t.number table_number,COALESCE(SUM(CASE WHEN p.status='valide' AND p.supprimer=0 THEN p.amount ELSE 0 END),0) paid FROM orders o LEFT JOIN tables t ON t.id=o.table_id LEFT JOIN payments p ON p.order_id=o.id WHERE o.supprimer=0 AND o.status<>'annuler' GROUP BY o.id HAVING paid<o.total_amount ORDER BY o.order_time DESC");$today=0;$total=0;$cancelled=0;foreach($payments as $p){if($p->status==='valide'){$total+=(float)$p->amount;if(date('Y-m-d',strtotime($p->payment_date))===date('Y-m-d'))$today+=(float)$p->amount;}else$cancelled++;}$methods=['especes'=>'Espèces','mobile_money'=>'Mobile Money','carte'=>'Carte','virement'=>'Virement'];$name=trim(($_SESSION['user_nom']??'Utilisateur').' '.($_SESSION['user_prenom']??''));$initials=strtoupper(substr($_SESSION['user_nom']??'U',0,1).substr($_SESSION['user_prenom']??'',0,1));
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Paiements — ISSALE</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet"><style>
:root{--p:#8B1A1A;--pd:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--side:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--green:#2d7d46;--red:#c0392b;--blue:#245c9e;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--side);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:30px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--p),var(--pd));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:4px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:12px 12px 5px}.nav{display:flex;align-items:center;gap:12px;padding:10px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:16px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;justify-content:space-between}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--p);text-decoration:none}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:22px}.stat{background:#fff;border:1px solid var(--border);border-radius:15px;padding:18px}.stat span{font-size:10px;text-transform:uppercase;color:var(--muted);font-weight:700}.stat strong{display:block;font:700 24px var(--display);margin-top:7px}.toolbar{display:flex;justify-content:space-between;gap:12px;margin-bottom:18px}.search{position:relative;max-width:360px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#999}.search input,.filter{padding:12px 14px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font)}.search input{width:100%;padding-left:40px}.tools{display:flex;gap:8px}.btn{border:0;border-radius:10px;padding:10px 13px;font:600 12px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:7px}.primary{background:var(--p);color:#fff}.light{background:#f4ede7}.danger{background:var(--red);color:#fff}.card{background:#fff;border:1px solid var(--border);border-radius:18px;overflow:hidden}.wrap{overflow:auto}table{width:100%;border-collapse:collapse}th{background:#fbf6f1;padding:13px 16px;text-align:left;text-transform:uppercase;font-size:10px;color:#94867e}td{padding:14px 16px;border-top:1px solid var(--border);font-size:12px;color:var(--muted)}tr:hover td{background:#fdf9f5}.payment strong{display:block;color:var(--text)}.badge{display:inline-block;padding:5px 8px;border-radius:99px;font-size:9px;font-weight:700}.valide{background:#e8f5ec;color:var(--green)}.annule{background:#fce8e8;color:var(--red)}.method{background:#e8f1ff;color:var(--blue)}.icon{width:31px;height:31px;border:1px solid var(--border);border-radius:8px;background:#fff;cursor:pointer;color:var(--red)}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(560px,100%);background:#fff;border-radius:20px}.head{display:flex;justify-content:space-between;padding:20px 23px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px}.body{padding:22px}.foot{display:flex;justify-content:flex-end;gap:8px;padding:17px 22px;border-top:1px solid var(--border)}.field{margin-bottom:14px}.field label{display:block;font-size:12px;font-weight:700;margin-bottom:6px}.field input,.field select{width:100%;padding:11px;border:1px solid var(--border);border-radius:10px}.balance{padding:12px;background:#fbf6f1;border-radius:10px;margin-bottom:14px}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:900px){.stats{grid-template-columns:repeat(2,1fr)}}@media(max-width:768px){.sidebar{transform:translateX(-100%)}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin:0}.menu-btn{display:block}.content{padding:18px 14px}.toolbar{flex-direction:column}.tools{flex-wrap:wrap}}
</style></head><body><aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav" href="commandes.php"><i class="bi bi-receipt"></i>Commandes</a><a class="nav active" href="paiements.php"><i class="bi bi-wallet2"></i>Paiements</a><a class="nav" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav" href="tables.php"><i class="bi bi-grid-3x3-gap"></i>Tables</a></nav><div class="user"><div class="avatar"><?=ph($initials)?></div><div><p><?=ph($name)?></p><span><?=ph(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div style="display:flex;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>Gestion des paiements</h2><small>Encaissements, soldes et historique</small></div></div></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> / Paiements</div><div class="stats"><div class="stat"><span>Encaissé aujourd'hui</span><strong><?=number_format($today,0,',',' ')?> FC</strong></div><div class="stat"><span>Total encaissé</span><strong><?=number_format($total,0,',',' ')?> FC</strong></div><div class="stat"><span>Commandes à solder</span><strong><?=count($orders)?></strong></div><div class="stat"><span>Paiements annulés</span><strong><?=$cancelled?></strong></div></div><div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterPayments()" placeholder="Commande, table ou référence…"></div><div class="tools"><select class="filter" id="methodFilter" onchange="filterPayments()"><option value="">Toutes les méthodes</option><?php foreach($methods as $key=>$label):?><option value="<?=ph($key)?>"><?=ph($label)?></option><?php endforeach;?></select><button class="btn primary" onclick="openPayment()"><i class="bi bi-plus-lg"></i>Nouveau paiement</button></div></div><div class="card"><div class="wrap"><table><thead><tr><th>Paiement</th><th>Commande / Table</th><th>Montant</th><th>Méthode</th><th>Référence</th><th>Statut</th><th>Action</th></tr></thead><tbody id="rows"><?php if(!$payments):?><tr><td colspan="7" style="text-align:center;padding:50px">Aucun paiement enregistré.</td></tr><?php endif;?><?php foreach($payments as $p):?><tr id="payment-<?=$p->id?>" data-method="<?=ph($p->payment_method)?>" data-search="<?=ph(strtolower($p->order_number.' '.$p->table_number.' '.$p->reference))?>"><td class="payment"><strong>#PAY-<?=$p->id?></strong><small><?=date('d/m/Y H:i',strtotime($p->payment_date))?></small></td><td><?=ph($p->order_number)?><br><small>Table <?=ph($p->table_number?:'—')?></small></td><td><strong><?=number_format((float)$p->amount,0,',',' ')?> FC</strong></td><td><span class="badge method"><?=ph($methods[$p->payment_method]??$p->payment_method)?></span></td><td><?=ph($p->reference?:'—')?></td><td><span class="badge <?=ph($p->status)?>"><?=ph(ucfirst($p->status))?></span></td><td><?php if($p->status==='valide'):?><button class="icon" onclick="askCancel(<?=$p->id?>,<?=ph(json_encode('#PAY-'.$p->id))?>)"><i class="bi bi-x-circle"></i></button><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></div></section></main>
<div class="overlay" id="paymentModal"><form class="modal" id="paymentForm" onsubmit="savePayment(event)"><div class="head"><h3>Enregistrer un paiement</h3><button type="button" class="close" onclick="paymentModal.classList.remove('open')">×</button></div><div class="body"><div class="field"><label>Commande *</label><select name="order_id" id="orderId" onchange="showBalance()" required><option value="">Sélectionner…</option><?php foreach($orders as $o):$remaining=(float)$o->total_amount-(float)$o->paid;?><option value="<?=$o->id?>" data-remaining="<?=$remaining?>"><?=ph($o->order_number)?> · Table <?=ph($o->table_number?:'—')?> · reste <?=number_format($remaining,0,',',' ')?> FC</option><?php endforeach;?></select></div><div class="balance" id="balance">Sélectionnez une commande.</div><div class="field"><label>Montant (FC) *</label><input type="number" name="amount" id="amount" min="1" required></div><div class="field"><label>Méthode *</label><select name="payment_method"><?php foreach($methods as $key=>$label):?><option value="<?=ph($key)?>"><?=ph($label)?></option><?php endforeach;?></select></div><div class="field"><label>Référence / Transaction</label><input name="reference" placeholder="Facultatif pour les espèces"></div></div><div class="foot"><button type="button" class="btn light" onclick="paymentModal.classList.remove('open')">Annuler</button><button class="btn primary" id="saveBtn">Encaisser</button></div></form></div>
<div class="overlay" id="cancelModal"><div class="modal" style="max-width:430px"><div class="head"><h3>Annuler le paiement</h3><button class="close" onclick="closeCancel()">×</button></div><div class="body" style="text-align:center"><div style="font-size:30px;color:var(--red)"><i class="bi bi-exclamation-triangle"></i></div><p>Annuler le paiement <strong id="cancelName"></strong> ?</p><small style="color:var(--red)">Le solde de la commande sera recalculé.</small></div><div class="foot"><button class="btn light" onclick="closeCancel()">Retour</button><button class="btn danger" onclick="executeCancel()">Annuler le paiement</button></div></div></div>
<script>
let cancelId=null;function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}function openPayment(){paymentForm.reset();balance.textContent='Sélectionnez une commande.';paymentModal.classList.add('open')}function showBalance(){const o=orderId.selectedOptions[0],r=Number(o?.dataset.remaining||0);balance.textContent=o?.value?'Solde restant : '+r.toLocaleString()+' FC':'Sélectionnez une commande.';amount.max=r||'';amount.value=r||''}async function api(data){const r=await fetch('../models/traitement/paiements-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});return r.json()}async function savePayment(e){e.preventDefault();saveBtn.disabled=true;const d=Object.fromEntries(new FormData(paymentForm));d.action='create';const o=await api(d);toast(o.message);if(o.success)setTimeout(()=>location.reload(),600);saveBtn.disabled=false}function askCancel(id,name){cancelId=id;cancelName.textContent=name;cancelModal.classList.add('open')}function closeCancel(){cancelModal.classList.remove('open');cancelId=null}async function executeCancel(){const o=await api({action:'cancel',id:cancelId});toast(o.message);if(o.success)setTimeout(()=>location.reload(),600)}function filterPayments(){const q=search.value.toLowerCase(),m=methodFilter.value;document.querySelectorAll('#rows tr[data-search]').forEach(r=>r.style.display=(!q||r.dataset.search.includes(q))&&(!m||r.dataset.method===m)?'':'none')}function toast(msg){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),3500)}[paymentModal,cancelModal].forEach(m=>m.onclick=e=>{if(e.target===m)m.classList.remove('open')});
</script><script src="../assets/js/sidebar-sync.js?v=3"></script></body></html>
